import { LoginRequest, RegisterRequest, ProxyUserAuthResponse } from '@/src/entities'

export default class UserClient {
    async register(registerData: RegisterRequest): Promise<ProxyUserAuthResponse> {
        const response = await fetch('/user/register', {
            method: "POST",
            body: JSON.stringify({
                username: registerData.username,
                password: registerData.password,
                name: registerData.name
            }),
            headers: {
                "Content-Type": "application/json"
            }
        })

        if (!response.ok) throw new Error(`Register failed with status code: ${response.status}`)
        const result: ProxyUserAuthResponse = await response.json()
        return result
    }

    async login (loginRequest: LoginRequest): Promise<ProxyUserAuthResponse> {
        const response = await fetch('/user/login', {
            method: "POST",
            body: JSON.stringify({
                username: loginRequest.username,
                password: loginRequest.password,
            }),
            headers: {
                "Content-Type": "application/json"
            }
        })

        if (!response.ok) throw new Error(`login failed with status code: ${response.status}`)
        const result: ProxyUserAuthResponse = await response.json()
        return result
    }

    async logout (): Promise<boolean> {
        const response = await fetch('/user/login', {
            method: "GET",
            headers: {
                "Content-Type": "application/json"
            }
        })

        if (!response.ok) throw new Error(`Logout failed with status code: ${response.status}`)
        return true
    }
}