import { UrlShortenerRequest, ShortenUrlResponse } from '@/src/entities'

export default class ShortenUrlClient {
    async shortenUrl(shortenUrlRequest: UrlShortenerRequest): Promise<ShortenUrlResponse> {
        const response = await fetch('/shorten-url', {
            method: "POST",
            body: JSON.stringify({
                original_irl: shortenUrlRequest.original_url
            }),
            headers: {
                "Content-Type": "application/json"
            }
        })

        if (!response.ok) throw new Error(`Shorten URL failed with HTTP status: ${response.status}`)
        const result: ShortenUrlResponse = await response.json()
        return result
    }
}
