import { LoginRequest, RegisterRequest } from '@/src/entities'

import { useUserStore } from "@/src/store/user-store"
import UserClient from '@/src/clients/user'

import useSWRMutation from 'swr/mutation'

export const useUser = () => {
    const userClient = new UserClient()
    const {
        setUserExpiry,
        setUserProfile
    } = useUserStore()

    function registerUser({
        successCallback,
        errorCallback
    }: {
        successCallback: (success: boolean) => void,
        errorCallback: (error: Error) => void
    }) {
        const { trigger, isMutating } = useSWRMutation(
            'register',
            async (key, { arg }: { arg: RegisterRequest}) => {
                const authResponse = await userClient.login(arg)
                setUserExpiry(authResponse.expiry)
                setUserProfile({
                    name: authResponse.name,
                    profile_pic: authResponse.profile_pic
                })
                return true
            }, {
                onSuccess: successCallback,
                onError: errorCallback
            }
        )

        return { trigger, isMutating }
    }

    function login({
        successCallback,
        errorCallback
    }: {
        successCallback: (success: boolean) => void,
        errorCallback: (error: Error) => void
    }) {
        const { trigger, isMutating } = useSWRMutation(
            'login',
            async (key, { arg }: { arg: LoginRequest}) => {
                const authResponse = await userClient.login(arg)
                setUserExpiry(authResponse.expiry)
                setUserProfile({
                    name: authResponse.name,
                    profile_pic: authResponse.profile_pic
                })
                return true
            }, {
                onSuccess: successCallback,
                onError: errorCallback
            }
        )

        return { trigger, isMutating }
    }

    function logout({
        successCallback,
        errorCallback
    }: {
        successCallback: (success: boolean) => void,
        errorCallback: (error: Error) => void
    }) {
        const { trigger, isMutating } = useSWRMutation(
            'logout',
            async () => {
                return await userClient.logout()
            }, {
                onSuccess: successCallback,
                onError: errorCallback
            }
        )

        return { trigger, isMutating }
    }

    return {
        registerUser,
        login,
        logout
    }
}